'use client'

import { useEffect } from 'react'

export default function Home() {
  useEffect(() => {
    // O middleware vai interceptar e redirecionar
    // Mas forçamos reload para garantir
    const timer = setTimeout(() => {
      window.location.reload()
    }, 100)
    return () => clearTimeout(timer)
  }, [])

  return (
    <div className="flex min-h-screen items-center justify-center bg-gradient-to-br from-red-50 to-orange-50">
      <div className="text-center">
        <div className="inline-block animate-spin rounded-full h-12 w-12 border-4 border-red-500 border-t-transparent mb-4"></div>
        <p className="text-gray-600">Carregando Nipo School...</p>
      </div>
    </div>
  )
}
